#include <bits/stdc++.h>
using namespace std;

const int INF = 1e9;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N, M;
    cin >> N >> M;
    vector<int> A(N);
    for (int i = 0; i < N; i++) {
        cin >> A[i];
    }

    // dp[s] = minimum cost to achieve total area s
    vector<int> dp(M + 1, INF);
    dp[0] = 0;

    for (int i = 0; i < N; i++) {
        vector<int> ndp(M + 1, INF);
        int a = A[i];
        for (int s = 0; s <= M; s++) {
            if (dp[s] == INF) continue;
            // try all possible new side lengths b (1..100) for this tile
            for (int b = 1; b <= 100; b++) {
                int area = b * b;
                if (s + area > M) break; // since b increases, area increases
                int cost = (a - b) * (a - b);
                ndp[s + area] = min(ndp[s + area], dp[s] + cost);
            }
        }
        dp = move(ndp);
    }

    int ans = dp[M];
    if (ans == INF) cout << -1 << "\n";
    else cout << ans << "\n";

    return 0;
}
